import{_ as e,o as r,c as i,ag as n}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Recruitment & ATS","description":"","frontmatter":{},"headers":[],"relativePath":"modules/recruitment.md","filePath":"modules/recruitment.md"}'),a={name:"modules/recruitment.md"};function o(d,t,s,l,c,g){return r(),i("div",null,[...t[0]||(t[0]=[n('<h1 id="recruitment-ats" tabindex="-1">Recruitment &amp; ATS <a class="header-anchor" href="#recruitment-ats" aria-label="Permalink to &quot;Recruitment &amp; ATS&quot;">​</a></h1><p>The Recruitment module provides a complete Applicant Tracking System (ATS) integrated directly into GeniusHRM. It covers the full hiring pipeline — from publishing job openings to extending offers and converting successful candidates into employees.</p><hr><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Navigate to <strong>HR Panel → Recruitment</strong> or <code>/recruitment</code>. The module includes:</p><table tabindex="0"><thead><tr><th>Section</th><th>URL</th><th>Description</th></tr></thead><tbody><tr><td><strong>Job Postings</strong></td><td><code>/recruitment/jobs</code></td><td>Create and manage open positions</td></tr><tr><td><strong>Applications</strong></td><td><code>/recruitment/applications</code></td><td>View and manage all candidates</td></tr><tr><td><strong>Pipeline Board</strong></td><td><code>/recruitment/board</code></td><td>Kanban-style stage management</td></tr><tr><td><strong>Interviews</strong></td><td><code>/recruitment/interviews</code></td><td>Schedule and record interviews</td></tr><tr><td><strong>Offers</strong></td><td><code>/recruitment/offers</code></td><td>Extend and track job offers</td></tr></tbody></table><hr><h2 id="job-postings" tabindex="-1">Job Postings <a class="header-anchor" href="#job-postings" aria-label="Permalink to &quot;Job Postings&quot;">​</a></h2><p>Job postings represent open vacancies that you are actively hiring for.</p><h3 id="creating-a-job-posting" tabindex="-1">Creating a Job Posting <a class="header-anchor" href="#creating-a-job-posting" aria-label="Permalink to &quot;Creating a Job Posting&quot;">​</a></h3><ol><li>Navigate to <strong>Recruitment → Jobs</strong></li><li>Click <strong>Post a Job</strong></li><li>Fill in the job details:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Job Title</strong></td><td>Yes</td><td>The position being advertised</td></tr><tr><td><strong>Department</strong></td><td>Yes</td><td>Which department this role belongs to</td></tr><tr><td><strong>Position</strong></td><td>Yes</td><td>Linked position from the Organisation module</td></tr><tr><td><strong>Location</strong></td><td>No</td><td>Office / Remote / Hybrid + city name</td></tr><tr><td><strong>Employment Type</strong></td><td>Yes</td><td>Full-time / Part-time / Contract / Intern</td></tr><tr><td><strong>Experience Required</strong></td><td>No</td><td>Minimum years of experience</td></tr><tr><td><strong>Salary Range</strong></td><td>No</td><td>Min and max salary (can be hidden from candidates)</td></tr><tr><td><strong>Application Deadline</strong></td><td>No</td><td>Last date for applications</td></tr><tr><td><strong>Job Description</strong></td><td>Yes</td><td>Rich text description of responsibilities</td></tr><tr><td><strong>Requirements</strong></td><td>Yes</td><td>Skills, qualifications, and experience required</td></tr><tr><td><strong>Status</strong></td><td>Yes</td><td>Draft / Active / Paused / Closed</td></tr></tbody></table><ol start="4"><li>Click <strong>Publish</strong> to make the posting active</li></ol><h3 id="job-posting-statuses" tabindex="-1">Job Posting Statuses <a class="header-anchor" href="#job-posting-statuses" aria-label="Permalink to &quot;Job Posting Statuses&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Draft</strong></td><td>Not yet visible; still being prepared</td></tr><tr><td><strong>Active</strong></td><td>Open for applications</td></tr><tr><td><strong>Paused</strong></td><td>Temporarily not accepting new applications</td></tr><tr><td><strong>Closed</strong></td><td>Position filled or abandoned</td></tr></tbody></table><hr><h2 id="application-pipeline-stages" tabindex="-1">Application Pipeline Stages <a class="header-anchor" href="#application-pipeline-stages" aria-label="Permalink to &quot;Application Pipeline Stages&quot;">​</a></h2><p>Every application progresses through a series of stages. The default pipeline stages are:</p><table tabindex="0"><thead><tr><th>Stage</th><th>Description</th></tr></thead><tbody><tr><td><strong>Applied</strong></td><td>Application received, not yet reviewed</td></tr><tr><td><strong>Screening</strong></td><td>Initial review by HR</td></tr><tr><td><strong>Interview</strong></td><td>Candidate invited for interview</td></tr><tr><td><strong>Assessment</strong></td><td>Technical test or assignment phase</td></tr><tr><td><strong>Offer</strong></td><td>Job offer extended</td></tr><tr><td><strong>Hired</strong></td><td>Offer accepted, ready for onboarding</td></tr><tr><td><strong>Rejected</strong></td><td>Not selected at any stage</td></tr><tr><td><strong>Withdrawn</strong></td><td>Candidate withdrew their application</td></tr></tbody></table><h3 id="pipeline-board-kanban-view" tabindex="-1">Pipeline Board (Kanban View) <a class="header-anchor" href="#pipeline-board-kanban-view" aria-label="Permalink to &quot;Pipeline Board (Kanban View)&quot;">​</a></h3><p>The <strong>Pipeline Board</strong> at <code>/recruitment/board</code> displays all active applications as cards in a Kanban layout, grouped by stage.</p><ul><li>Drag and drop cards between stage columns to advance candidates</li><li>Click a card to view the full application</li><li>Filter by Job Posting to see candidates for a specific role</li></ul><hr><h2 id="managing-candidates" tabindex="-1">Managing Candidates <a class="header-anchor" href="#managing-candidates" aria-label="Permalink to &quot;Managing Candidates&quot;">​</a></h2><h3 id="viewing-applications" tabindex="-1">Viewing Applications <a class="header-anchor" href="#viewing-applications" aria-label="Permalink to &quot;Viewing Applications&quot;">​</a></h3><p>From <strong>Recruitment → Applications</strong>, you can see all submissions with:</p><table tabindex="0"><thead><tr><th>Column</th><th>Description</th></tr></thead><tbody><tr><td>Candidate Name</td><td>Full name</td></tr><tr><td>Job Posting</td><td>Which role they applied for</td></tr><tr><td>Current Stage</td><td>Pipeline stage</td></tr><tr><td>Applied Date</td><td>When the application was submitted</td></tr><tr><td>Source</td><td>How they applied (Job Board, Referral, etc.)</td></tr><tr><td>Rating</td><td>Recruiter&#39;s star rating (1–5)</td></tr></tbody></table><h3 id="candidate-profile" tabindex="-1">Candidate Profile <a class="header-anchor" href="#candidate-profile" aria-label="Permalink to &quot;Candidate Profile&quot;">​</a></h3><p>Each application has a detailed profile:</p><ul><li><strong>Summary</strong> — Stage, applied date, source, notes</li><li><strong>Resume/CV</strong> — Uploaded document (PDF or DOCX)</li><li><strong>Cover Letter</strong> — Text or uploaded file</li><li><strong>Personal Details</strong> — Name, email, phone, LinkedIn</li><li><strong>Interview History</strong> — All scheduled and completed interviews</li><li><strong>Notes &amp; Feedback</strong> — Internal recruiter notes</li><li><strong>Timeline</strong> — Stage change history with dates and notes</li></ul><h3 id="adding-notes" tabindex="-1">Adding Notes <a class="header-anchor" href="#adding-notes" aria-label="Permalink to &quot;Adding Notes&quot;">​</a></h3><ol><li>Open the candidate profile</li><li>Click <strong>Add Note</strong></li><li>Type your note (supports markdown)</li><li>Click <strong>Save Note</strong></li></ol><p>Notes are visible to all recruiters and HR managers but not to the candidate.</p><hr><h2 id="interview-scheduling" tabindex="-1">Interview Scheduling <a class="header-anchor" href="#interview-scheduling" aria-label="Permalink to &quot;Interview Scheduling&quot;">​</a></h2><h3 id="scheduling-an-interview" tabindex="-1">Scheduling an Interview <a class="header-anchor" href="#scheduling-an-interview" aria-label="Permalink to &quot;Scheduling an Interview&quot;">​</a></h3><ol><li>From the candidate profile, click <strong>Schedule Interview</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Required</th><th>Description</th></tr></thead><tbody><tr><td><strong>Interview Type</strong></td><td>Yes</td><td>Phone / Video / In-person / Technical</td></tr><tr><td><strong>Interview Date</strong></td><td>Yes</td><td>Date and time</td></tr><tr><td><strong>Duration</strong></td><td>No</td><td>Expected length in minutes</td></tr><tr><td><strong>Interviewer(s)</strong></td><td>Yes</td><td>Select from employee list</td></tr><tr><td><strong>Location / Link</strong></td><td>No</td><td>Room name or video call URL</td></tr><tr><td><strong>Notes</strong></td><td>No</td><td>Preparation notes for interviewers</td></tr></tbody></table><ol start="3"><li>Click <strong>Schedule</strong></li></ol><p>The candidate is moved to the <strong>Interview</strong> stage. Interviewers receive an email notification.</p><h3 id="recording-interview-feedback" tabindex="-1">Recording Interview Feedback <a class="header-anchor" href="#recording-interview-feedback" aria-label="Permalink to &quot;Recording Interview Feedback&quot;">​</a></h3><p>After the interview:</p><ol><li>Open the candidate profile</li><li>Click the scheduled interview entry</li><li>Click <strong>Add Feedback</strong></li><li>Rate the candidate (1–5 stars)</li><li>Add detailed notes</li><li>Select a recommendation: <strong>Proceed</strong>, <strong>Hold</strong>, <strong>Reject</strong></li><li>Click <strong>Submit Feedback</strong></li></ol><hr><h2 id="extending-an-offer" tabindex="-1">Extending an Offer <a class="header-anchor" href="#extending-an-offer" aria-label="Permalink to &quot;Extending an Offer&quot;">​</a></h2><p>When a candidate reaches the <strong>Offer</strong> stage:</p><ol><li>Click <strong>Create Offer</strong></li><li>Fill in:</li></ol><table tabindex="0"><thead><tr><th>Field</th><th>Description</th></tr></thead><tbody><tr><td><strong>Position</strong></td><td>Confirmed job title</td></tr><tr><td><strong>Department</strong></td><td>Department</td></tr><tr><td><strong>Start Date</strong></td><td>Proposed first day</td></tr><tr><td><strong>Salary</strong></td><td>Offered compensation</td></tr><tr><td><strong>Offer Expiry Date</strong></td><td>Deadline for candidate to respond</td></tr><tr><td><strong>Terms &amp; Conditions</strong></td><td>Custom offer letter text</td></tr></tbody></table><ol start="3"><li>Click <strong>Send Offer</strong></li></ol><p>The system generates an offer letter PDF and emails it to the candidate.</p><h3 id="offer-status-tracking" tabindex="-1">Offer Status Tracking <a class="header-anchor" href="#offer-status-tracking" aria-label="Permalink to &quot;Offer Status Tracking&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Status</th><th>Description</th></tr></thead><tbody><tr><td><strong>Sent</strong></td><td>Offer emailed to candidate</td></tr><tr><td><strong>Accepted</strong></td><td>Candidate accepted</td></tr><tr><td><strong>Rejected</strong></td><td>Candidate declined</td></tr><tr><td><strong>Expired</strong></td><td>Expiry date passed with no response</td></tr></tbody></table><hr><h2 id="onboarding-—-converting-to-employee" tabindex="-1">Onboarding — Converting to Employee <a class="header-anchor" href="#onboarding-—-converting-to-employee" aria-label="Permalink to &quot;Onboarding — Converting to Employee&quot;">​</a></h2><p>When an offer is <strong>Accepted</strong>, the candidate can be converted to a full employee record:</p><ol><li>Open the accepted offer</li><li>Click <strong>Convert to Employee</strong></li><li>The system pre-fills the New Employee form with the candidate&#39;s data</li><li>Review and complete any missing fields</li><li>Click <strong>Save Employee</strong></li></ol><p>The employee record is created with a status of <strong>Active</strong> and linked to the recruitment record for audit purposes.</p><hr><h2 id="recruitment-reports" tabindex="-1">Recruitment Reports <a class="header-anchor" href="#recruitment-reports" aria-label="Permalink to &quot;Recruitment Reports&quot;">​</a></h2><p>From <strong>Reports → Recruitment</strong>:</p><ul><li>Open positions count</li><li>Applications by stage (funnel chart)</li><li>Time-to-hire per role</li><li>Source effectiveness (which channels bring the best candidates)</li><li>Offer acceptance rate</li></ul>',61)])])}const u=e(a,[["render",o]]);export{p as __pageData,u as default};
